const { data, schema } = $('📥 Input').first().json;
if (!data || !schema) throw new Error('data und schema sind erforderlich');
const errors = [];
for (const [key, def] of Object.entries(schema.properties || {})) {
  if (def.required && data[key] === undefined) errors.push(`${key} ist erforderlich`);
  if (data[key] !== undefined && typeof data[key] !== def.type && def.type !== 'any') errors.push(`${key} muss ${def.type} sein`);
}
return { exit_code: errors.length === 0 ? 'success' : 'failed',
  session_id: require('crypto').randomUUID(),
  data: { valid: errors.length === 0, errors },
  timestamp: new Date().toISOString() };
